INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$37c52dcf-d489-4b31-bbd3-ded5a1194dfd$tag$, $tag$2026010500147$tag$, $tag$RosÃ¢ngela (5511973575502)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Olá","time":"05/01/2026 15:36:17"},{"role":"client","text":"🌟 Boa tarde RosÃ¢ngela! Que alegria ter você aqui com a gente! 🙌","time":"05/01/2026 15:36:18"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"05/01/2026 15:36:22"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"05/01/2026 15:36:25"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"05/01/2026 15:36:29"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"05/01/2026 15:36:35"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"05/01/2026 15:36:41"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"05/01/2026 15:36:42"},{"role":"client","text":"Sim, concordo","time":"05/01/2026 15:42:54"},{"role":"client","text":"✅ Obrigado, RosÃ¢ngela! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"05/01/2026 15:42:56"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"05/01/2026 15:43:00"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"05/01/2026 15:44:08"},{"role":"client","text":"Olá! RosÃ¢ngela!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"05/01/2026 15:44:09"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"05/01/2026 15:44:13"},{"role":"client","text":"Saber sobre os cursos","time":"05/01/2026 15:45:15"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"05/01/2026 15:45:19"},{"role":"client","text":"Graduação","time":"05/01/2026 15:45:40"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"05/01/2026 15:45:44"},{"role":"client","text":"Cursos livres","time":"05/01/2026 15:45:49"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"05/01/2026 15:45:50"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"05/01/2026 15:45:54"},{"role":"client","text":"Teologia (Presencial)","time":"05/01/2026 15:45:58"},{"role":"client","text":"✨ Você escolheu a modalidade presencial em João Pessoa!\nEssa é uma graduação com estrutura moderna, ensino prático desde o início e visão teológica fundamentada nas Escrituras, na tradição dos apóstolos e dos Pais da Igreja.\n\n\n 🎓 Curso reconhecido pelo MEC\n 🔠 Ensino de Grego e Hebraico\n 📌 Prática eclesiástica e liderança desde o início\n 🪙 Matrículas abertas com vagas promocionais!\n","time":"05/01/2026 15:45:59"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"05/01/2026 15:46:02"},{"role":"client","text":"Teologia (EAD)","time":"05/01/2026 15:46:08"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"05/01/2026 15:46:09"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"05/01/2026 15:46:13"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"05/01/2026 15:46:23"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"05/01/2026 15:46:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 15:48:53"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"05/01/2026 15:49:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"05/01/2026 15:49:25","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"05/01/2026 15:49:29","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"05/01/2026 15:50:05","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"05/01/2026 15:50:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"05/01/2026 17:20:33","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Ainda não, acho que ainda não vai dar, por conta $$","time":"05/01/2026 17:24:37"},{"role":"client","text":"Mas agradeço atenção de vcs!","time":"05/01/2026 17:24:45"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\n\nTenho uma ótima noticia, consegui mais desconto para você, mais 10% de desconto, totalizando 30% de desconto em *todo o curso*, as mensalidades ficam de R$ 279,79\n\nVamos aproveitar esse desconto?","time":"06/01/2026 08:14:38","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nRosÃ¢ngela, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"07/01/2026 09:56:00"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"07/01/2026 09:56:01"},{"role":"client","text":"RosÃ¢ngela, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"07/01/2026 10:11:01"}]$tag$, $tag$2026-01-05 15:36:17+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXC