INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$bc4b4e94-372c-456f-86fc-360b4d1460bc$tag$, $tag$2026010500202$tag$, $tag$Cláudio (5511971826218)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"05/01/2026 23:35:31"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"05/01/2026 23:35:32"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"06/01/2026 08:07:30"},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"06/01/2026 08:07:55","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"06/01/2026 08:08:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"06/01/2026 08:08:10","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"06/01/2026 08:08:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nCláudio, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"07/01/2026 09:55:53"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"09/01/2026 08:05:31"},{"role":"client","text":"Sua sessão expirou!","time":"09/01/2026 08:07:32"}]$tag$, $tag$2026-01-05 23:35:31+00$tag$, FALSE, FALSE, 5.8, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 3, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$85874d27-3a05-41c6-a96d-2b1852deef9e$tag$, $tag$2026010600003$tag$, $tag$Sam (5592991754430)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"06/01/2026 01:47:04"},{"role":"client","text":"🌟 Boa noite Sam! Que alegria ter você aqui com a gente! 🙌","time":"06/01/2026 01:47:05"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"06/01/2026 01:47:09"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"06/01/2026 01:47:13"},{"role":"client","text":"Quais as pós graduação","time":"06/01/2026 01:47:16"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"06/01/2026 01:47:17"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"06/01/2026 01:47:22"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"06/01/2026 01:47:28"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"06/01/2026 01:47:29"},{"role":"client","text":"Sim, concordo","time":"06/01/2026 01:47:48"},{"role":"client","text":"✅ Obrigado, Sam! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"06/01/2026 01:47:49"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"06/01/2026 01:47:52"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"06/01/2026 01:48:08"},{"role":"client","text":"Olá! Sam!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"06/01/2026 01:48:08"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"06/01/2026 01:48:12"},{"role":"client","text":"Saber sobre os cursos","time":"06/01/2026 01:48:29"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"06/01/2026 01:48:33"},{"role":"client","text":"Pós-Graduação","time":"06/01/2026 01:48:42"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"06/01/2026 01:48:46"},{"role":"client","text":"Teologia Sistemática","time":"06/01/2026 01:48:59"},{"role":"client","text":"Aprofunde-se na fé cristã com uma base teológica sólida e estruturada.\n 📚 Estudos em Doutrina de Deus, Cristologia, Soteriologia, Pneumatologia e mais\n 📌 Voltado para teólogos, pastores e educadores\n 🎓 Professores mestres e doutores na área\n","time":"06/01/2026 01:49:00"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"06/01/2026 01:49:04"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"06/01/2026 01:49:22"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"06/01/2026 01:49:23"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"06/01/2026 01:49:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"06/01/2026 08:09:39"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"06/01/2026 08:10:26","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:*  *Pós-Graduação em Teologia Sistemática* \n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"06/01/2026 08:10:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* TEOLOGIA SISTEMÁTICA - DISCIPLINAS DO CURSO:\n\nFUNDAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeoria do Método Teológico e Teologia Fundamental\nTeologia Pastoral e Missiológica \nHistória da Teologia Cristã \nPerspectivas Teológico-filosóficas na pós modernidade\n\nDESDOBRAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeontologia e Trindade\nCristologia \nPneumatologia e Teologia Pentecostal\nBibliologia\nAntropologia Teológica e Hamartiologia\nSoteriologia \nEclesiologia\nEscatologia \n\nObs: Professores sujeitos a alterações. ","time":"06/01/2026 08:10:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Teologia Sistemática está em 16 mensalidades de *R$ 359,37*. Esse mês esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.\n\n\n🎁 Cupom de Desconto Teologia Sistemática: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_25\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"06/01/2026 08:10:47","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Atendimento Finalizado!\n\nSam, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"07/01/2026 09:56:14"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"07/01/2026 09:56:16"},{"role":"client","text":"Sam, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"07/01/2026 10:11:17"}]$tag$, $tag$2026-01-06 01:47:04+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
