INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$9c19edbf-2d83-4433-8930-9f8cad25abc9$tag$, $tag$2026010800090$tag$, $tag$2020.1 TEO PRE Samara Albuquerque Matias (5583981340704)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Saber sobre os cursos","time":"08/01/2026 11:38:48"},{"role":"client","text":"🌟 Bom dia 2020.1 TEO PRE Samara Albuquerque Matias! Que alegria ter você aqui com a gente! 🙌","time":"08/01/2026 11:38:49"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"08/01/2026 11:38:53"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"08/01/2026 11:38:57"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"08/01/2026 11:39:04"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"08/01/2026 11:39:13"},{"role":"client","text":"Olá! 2020.1 TEO PRE Samara Albuquerque Matias!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"08/01/2026 11:39:14"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"08/01/2026 11:39:18"},{"role":"client","text":"Saber sobre os cursos","time":"08/01/2026 11:39:31"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"08/01/2026 11:39:35"},{"role":"client","text":"Graduação","time":"08/01/2026 11:39:46"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"08/01/2026 11:39:51"},{"role":"client","text":"Teologia (Presencial)","time":"08/01/2026 11:40:09"},{"role":"client","text":"✨ Você escolheu a modalidade presencial em João Pessoa!\nEssa é uma graduação com estrutura moderna, ensino prático desde o início e visão teológica fundamentada nas Escrituras, na tradição dos apóstolos e dos Pais da Igreja.\n\n\n 🎓 Curso reconhecido pelo MEC\n 🔠 Ensino de Grego e Hebraico\n 📌 Prática eclesiástica e liderança desde o início\n 🪙 Matrículas abertas com vagas promocionais!\n","time":"08/01/2026 11:40:10"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"08/01/2026 11:40:14"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"08/01/2026 11:43:38"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"08/01/2026 11:43:39"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"08/01/2026 11:45:01"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"08/01/2026 11:45:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Bom dia","time":"08/01/2026 11:45:39"},{"role":"agent","text":"*Karina Pimentel:*  A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 20%* na pontualidade durante toda graduação, que fica apenas R$ 439,64.  *Usando o cupom de desconto: BOLSA20*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.637,88).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 439,64 = R$ 2.637,88\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 527,57 = R$ 2.637,88\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 659,47 = R$ 2.637,88\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"08/01/2026 11:45:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Queria voltar a cursar teologia","time":"08/01/2026 11:45:59"},{"role":"agent","text":"*Karina Pimentel:* Já realizava conosco?","time":"08/01/2026 11:47:12","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Já sim","time":"08/01/2026 11:48:01"},{"role":"client","text":"087.825.834-55","time":"08/01/2026 11:48:08"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"08/01/2026 11:49:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe transferir na Secretaria para maiores informações ok!","time":"08/01/2026 11:49:40","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Karina Pimentel transferiu o atendimento para a equipe FICV - SECRETARIA","time":"08/01/2026 11:49:49"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Abel Alves","time":"08/01/2026 11:51:09"},{"role":"client","text":"Boa tarde","time":"08/01/2026 12:02:12"},{"role":"client","text":"*Abel Alves:* Olá, boa tarde. ","time":"08/01/2026 12:07:19"},{"role":"client","text":"*Abel Alves:* Como posso ajudar ?","time":"08/01/2026 12:07:22"},{"role":"client","text":"Gostaria de saber como faço para voltar a cursar teologia","time":"08/01/2026 12:07:51"},{"role":"client","text":"Abel Alves transferiu o atendimento para a equipe FICV - COMERCIAL","time":"08/01/2026 12:08:11"},{"role":"client","text":"Boa tarxe","time":"08/01/2026 12:30:10"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"08/01/2026 13:20:49"},{"role":"client","text":"Oi","time":"08/01/2026 13:21:08"},{"role":"client","text":".","time":"08/01/2026 13:21:14"},{"role":"client","text":".","time":"08/01/2026 13:21:16"},{"role":"agent","text":"*Karina Pimentel:* Me informe seu nome completo por gentileza!","time":"08/01/2026 13:21:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Samara Albuquerque Matuas","time":"08/01/2026 13:21:20"},{"role":"client","text":"Matias*","time":"08/01/2026 13:21:27"},{"role":"agent","text":"*Karina Pimentel:* Faz muito tempo que cursou conosco?","time":"08/01/2026 13:23:40","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Parei na pandemia","time":"08/01/2026 13:24:05"},{"role":"agent","text":"*Karina Pimentel:* Cursou 1 período apenas?","time":"08/01/2026 14:19:43","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Acho q o 3 não ?","time":"08/01/2026 14:20:20"},{"role":"agent","text":"*Karina Pimentel:* Vou ver se conseguem rastrear, pois mudamos de sistema e não consigo visualizar aqui ok!","time":"08/01/2026 14:31:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Lhe retorno já está bem!","time":"08/01/2026 14:33:49","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok","time":"08/01/2026 14:38:15"},{"role":"agent","text":"*Karina Pimentel:* Senhora seria para retornar presencial ou Ead?","time":"08/01/2026 17:08:42","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Como está as modalidades?","time":"08/01/2026 17:09:00"},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 30%* na pontualidade durante toda graduação, que fica apenas R$ 384,69.  *Usando o cupom de desconto: BOLSA30*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.308,15).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 384,69 = R$ 2.308,15\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 461,63 = R$ 2.308,15\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 577,03 = R$ 2.308,15\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"08/01/2026 17:09:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56","time":"08/01/2026 17:10:25","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Certo, vou analisar","time":"08/01/2026 17:32:47"},{"role":"client","text":"Quando volta as aulas","time":"08/01/2026 17:32:50"},{"role":"agent","text":"*Karina Pimentel:* Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"09/01/2026 10:40:53","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* 02/02","time":"09/01/2026 10:41:00","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\n2020.1 TEO PRE Samara Albuquerque Matias, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 16:20:13"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"09/01/2026 16:20:14"},{"role":"client","text":"2020.1 TEO PRE Samara Albuquerque Matias, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"09/01/2026 16:35:15"}]$tag$, $tag$2026-01-08 11:38:48+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 17, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$9a471640-de99-4400-898a-d396dd6475da$tag$, $tag$2026010800103$tag$, $tag$Castro (5587991526811)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"08/01/2026 12:11:14"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"08/01/2026 12:11:15"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"08/01/2026 13:09:04"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"08/01/2026 13:09:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"08/01/2026 13:09:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"08/01/2026 13:09:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"08/01/2026 13:09:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"08/01/2026 13:09:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"09/01/2026 08:11:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nCastro, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 12:23:24"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"11/01/2026 12:09:17"},{"role":"client","text":"Sua sessão expirou!","time":"11/01/2026 12:11:19"}]$tag$, $tag$2026-01-08 12:11:14+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
