INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$ed5d5e0b-864d-41c4-9dbf-e99b288ebbcd$tag$, $tag$2026010600085$tag$, $tag$Lidiane Cardoso (5524999558029)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"oi","time":"06/01/2026 13:30:36"},{"role":"client","text":"🌟 Boa tarde Lidiane Cardoso! Que alegria ter você aqui com a gente! 🙌","time":"06/01/2026 13:30:37"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"06/01/2026 13:30:41"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"06/01/2026 13:30:45"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"06/01/2026 13:30:49"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"06/01/2026 13:30:55"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"06/01/2026 13:31:01"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"06/01/2026 13:31:01"},{"role":"client","text":"Sim, concordo","time":"06/01/2026 13:32:09"},{"role":"client","text":"✅ Obrigado, Lidiane Cardoso! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"06/01/2026 13:32:10"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"06/01/2026 13:32:14"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"06/01/2026 13:32:38"},{"role":"client","text":"Olá! Lidiane Cardoso!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"06/01/2026 13:32:38"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"06/01/2026 13:32:42"},{"role":"client","text":"Falar com um atendente","time":"06/01/2026 13:33:02"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"06/01/2026 13:33:03"},{"role":"client","text":"Pós Graduação em Educação Clássica","time":"06/01/2026 13:33:26"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"06/01/2026 13:50:55"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"06/01/2026 13:51:07","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"06/01/2026 13:51:21","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Oi Karina,  boa tarde","time":"06/01/2026 13:51:26"},{"role":"client","text":"Tudo bem?!","time":"06/01/2026 13:51:32"},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"06/01/2026 13:51:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Tudo ótimo e a senhora?","time":"06/01/2026 13:51:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Tudo bem tbm graças a Deus","time":"06/01/2026 13:52:55"},{"role":"client","text":"As mensalidades são pagas via cartão?","time":"06/01/2026 13:53:08"},{"role":"client","text":"E serão 16 meses de curso?","time":"06/01/2026 13:53:29"},{"role":"agent","text":"*Karina Pimentel:* Pix, Boleto ou Cartão.","time":"06/01/2026 13:54:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Quais materiais e livros são recomendados para serem adquiridos ao longo do curso??","time":"06/01/2026 13:54:26"},{"role":"agent","text":"*Karina Pimentel:* Isso.","time":"06/01/2026 13:54:32","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Já passa o valor integral e vai descontando mensalmente?","time":"06/01/2026 13:54:52"},{"role":"client","text":"Ou pago a primeira agora e depois só em abril?","time":"06/01/2026 13:55:09"},{"role":"client","text":"Como funciona?","time":"06/01/2026 13:55:11"},{"role":"agent","text":"*Karina Pimentel:* Pode pagar mensalmente sem problemas!","time":"06/01/2026 13:55:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Vocês enviam link de pagamento?","time":"06/01/2026 13:56:17"},{"role":"agent","text":"*Karina Pimentel:* Os boletos ficarão na Plataforma do aluno para retira-los mensalmente.","time":"06/01/2026 17:11:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi","time":"06/01/2026 17:12:26"},{"role":"client","text":"E porque as aulas começam apenas em abril?","time":"06/01/2026 17:12:38"},{"role":"agent","text":"*Karina Pimentel:* Porque será inicio do curso.","time":"06/01/2026 17:16:10","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Não libera o acesso antes!","time":"06/01/2026 17:16:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi","time":"06/01/2026 17:20:44"},{"role":"client","text":"Terá alguma aula ao vivo ou todas gravadas?","time":"06/01/2026 17:21:05"},{"role":"client","text":"Bom dia","time":"08/01/2026 07:05:11"},{"role":"client","text":"Pode me confirmar?","time":"08/01/2026 07:20:04"},{"role":"client","text":"Poderia me confirmar tbm sobre os professores?","time":"08/01/2026 07:20:21"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"08/01/2026 08:45:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Kari