INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2726391e-bdd5-47be-b75f-26fcf789727e$tag$, $tag$2026010700020$tag$, $tag$Wender Cardoso (5583996190341)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"07/01/2026 08:14:54"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"07/01/2026 08:14:55"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"07/01/2026 08:26:40"},{"role":"client","text":"Olá bom dia Karina!","time":"07/01/2026 08:30:25"},{"role":"client","text":"Gostaria de saber o valor da graduação em teologia ,  pós em psicopedagogia e se quem é membro tem direito a alguma bolsa","time":"07/01/2026 08:31:20"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"07/01/2026 08:33:51","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOPEDAGOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 18 meses.\n\nCARGA HORÁRIA\n630 horas\n\nDISCIPLINAS\n12 disciplinas obrigatórias e 1  disciplina optativa\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"07/01/2026 08:34:22","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Psicopedagogia será de: 18 mensalidades de R$ 479,16.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026.","time":"07/01/2026 08:35:05","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tem alguma bolsa pra quem é membro da cidade viva ?","time":"07/01/2026 09:21:35"},{"role":"client","text":"É voluntário","time":"07/01/2026 09:21:46"},{"role":"agent","text":"*Karina Pimentel:* Temos desconto sim.","time":"07/01/2026 09:34:42","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 50% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 239,58.\nVamos garantir a sua vaga? 😊","time":"07/01/2026 09:35:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Muito bom !","time":"07/01/2026 09:45:27"},{"role":"agent","text":"*Karina Pimentel:* Vamos garantir a sua vaga?","time":"07/01/2026 11:07:14","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Faltou você me passar de teologia","time":"07/01/2026 11:07:35"},{"role":"agent","text":"*Karina Pimentel:* 🎁 Cupom de Desconto da Pós em Psicopedagogia: BOLSA50\n\n📌 Realize sua matrícula no link: https://bit.ly/PosPsicopedagogiaFICV\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"07/01/2026 11:07:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Passo já!","time":"07/01/2026 11:08:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma M","time":"07/01/2026 11:08:24","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"07/01/2026 11:08:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"No momento eu não vou fazer a matrícula ainda  estou me programando ainda","time":"07/01/2026 11:09:02"},{"role":"client","text":"Ainda tem desconto pra membro e voluntário ?","time":"07/01/2026 11:10:11"},{"role":"agent","text":"*Karina Pimentel:* Podemos verificar sim.","time":"07/01/2026 13:25:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"08/01/2026 14:07:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá Karina","time":"08/01/2026 14:08:10"},{"role":"client","text":"Boa tarde!","time":"08/01/2026 14:08:13"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"08/01/2026 14:46:29","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Conseguimos um desconto especial de 30%, vamos garantir a sua vaga?","time":"08/01/2026 14:46:48","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Quanto fica ?","time":"08/01/2026 17:00:41"},{"role":"agent","text":"*Karina Pimentel:* R$ 279,79 mensais","time":"08/01/2026 17:13:07","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"09/01/2026 10:40:26","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Karina bom dia !","time":"09/01/2026 10:40:52"},{"role":"client","text":"O valor está ótimo mas ainda não vai caber no meu orçamento atual. Eu vi que vocês tem a opção semestral e que acredito ficará mais viável pra mim em breve entrarei em contato para isso. Agradeço gentilmente toda a atenção.","time":"09/01/2026 10:42:01"},{"role":"client","text":"Só mais uma pergunta essas aulas tem horário certo ? Ou o ajuste de horário é feito pelo aluno on-line","time":"09/01/2026 10:42:46"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"09/01/2026 10:48:12","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* São gravadas as aulas, quando ocorrem aulas ao vivo, serão avisadas com antecedência! ","time":"09/01/2026 10:48:53","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nWender Cardoso, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 16:21:14"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"12/01/2026 10:40:47"},{"role":"client","text":"Sua sessão expirou!","time":"12/01/2026 10:42:49"}]$tag$, $tag$2026-01-07 08:14:54+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 18, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_c