INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$e9ae1963-4066-4399-ac01-691731af8f07$tag$, $tag$2026010700102$tag$, $tag$Lucymar Ramos (5581993970691)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"07/01/2026 10:58:01"},{"role":"client","text":"🌟 Bom dia Lucymar Ramos! Que alegria ter você aqui com a gente! 🙌","time":"07/01/2026 10:58:02"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"07/01/2026 10:58:05"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"07/01/2026 10:58:09"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"07/01/2026 10:58:14"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"07/01/2026 10:58:19"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"07/01/2026 10:58:26"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"07/01/2026 10:58:26"},{"role":"client","text":"Sim, concordo","time":"07/01/2026 10:58:52"},{"role":"client","text":"✅ Obrigado, Lucymar Ramos! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"07/01/2026 10:58:52"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"07/01/2026 10:58:56"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"07/01/2026 10:59:11"},{"role":"client","text":"Olá! Lucymar Ramos!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"07/01/2026 10:59:12"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"07/01/2026 10:59:16"},{"role":"client","text":"Saber sobre os cursos","time":"07/01/2026 10:59:30"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"07/01/2026 10:59:34"},{"role":"client","text":"Pós-Graduação","time":"07/01/2026 10:59:44"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"07/01/2026 10:59:48"},{"role":"client","text":"Gestão Escolar","time":"07/01/2026 11:00:00"},{"role":"client","text":"Forme-se como um líder educacional com visão estratégica, conhecimento de legislação e práticas pedagógicas atuais.\n\n 📌 Ideal para gestores, coordenadores e professores\n 🌐 Curso 100% EAD — estude de onde estiver\n 🗓️ Início das aulas em agosto\n 🎁 Condições especiais para novas matrículas\n","time":"07/01/2026 11:00:01"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"07/01/2026 11:00:05"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"07/01/2026 11:00:19"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"07/01/2026 11:00:20"},{"role":"client","text":"Ok","time":"07/01/2026 11:00:37"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"07/01/2026 11:08:43"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações","time":"07/01/2026 11:08:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:*  PÓS-GRADUAÇÃO EM GESTÃO ESCOLAR.\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n480 horas + 2 disciplinas optativas\n\nDISCIPLINAS\nDisciplinas: 12 + 2 disciplinas optativas\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"07/01/2026 11:09:13","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Obrigada","time":"07/01/2026 11:09:16"},{"role":"agent","text":"*Thayanne Sales:*  *Disciplinas da Pós em Gestão Escolar*\n\nBASE: PEDAGÓGICA\n\n1-Educação e Cosmovisão Cristã - Prof. Ms. Thiago\nDutra\n2-Fundamentos Filosóficos e\nMetodológicos da Educação\nCristã - Prof. Ms. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Prof. Ms. ThiagoDutra\n4-Apoio Psicopedagógico,\nAprendizagem mediada e\nInclusão - Prof. Ms.Fabiana Sousa\n5-Disciplina Virtuosa (50%\ngravada) - Prof. Esp. Filipe Asafe/ Profª. Letícia Ruiz Alves\n\nBASE: PLANEJAMENTO E LEGISLAÇÃO\n\n6-Planejamento Estratégico:Missão, Visão e Valores.Definição das estratégias eobjetivos estratégicos\nPlanos de ação e indicadores - Prof. Dr.Josemar Bandeira\n7-Estrutura Básica do Sistema Educacional Brasileiro - Prof. Esp.Edmilson Almeida\n8-Projeto Político Pedagógico e Regimento Interno - Prof. Ms. Thiago Dutra\n\nBASE: GESTÃO ESCOLAR\n\n9-Gestão de Pessoas e Cultura Organizacional - Profª. Esp.Patrícia Queiroz\n10-Gestão por Processos 40 Prof. Ms. Renato Assis\n11-Gestão de Marketing 40 Prof. Dr.Josemar Bandeira\n12-Gestão Financeira 40 Prof. Ms. Renato Assis\n\n- Módulo optativo: Formação para Coordenadores Pedagógicos\n- Módulo optativo: Incubadora de Novas Escolas","time":"07/01/2026 11:09:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Gestão Escolar está em 16 mensalidades de *R$ 479,16*. Esse mês esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.\n\n\n🎁 Cupom de Desconto da Pós em Gestão Escolar: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_24\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"07/01/2026 11:09:26","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Perfeito,  vou querer sim.\nAssim que fizer a inscrição te enviarei. \nMuito obrigada. \nDeus abençoe 🙌","time":"07/01/2026 11:14:09"},{"role":"agent","text":"*Thayanne Sales:* Ta certo, fico no aguardo de um retorno","