INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$275ef353-38e4-41cb-a857-e499bb361d78$tag$, $tag$2026010800069$tag$, $tag$AndreQM (5511971703350)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"08/01/2026 10:25:54"},{"role":"client","text":"🌟 Bom dia AndreQM! Que alegria ter você aqui com a gente! 🙌","time":"08/01/2026 10:25:55"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"08/01/2026 10:25:59"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"08/01/2026 10:26:02"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"08/01/2026 10:26:09"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"08/01/2026 10:27:27"},{"role":"client","text":"Olá! AndreQM!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"08/01/2026 10:27:28"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"08/01/2026 10:27:32"},{"role":"client","text":"Falar com um atendente","time":"08/01/2026 10:27:43"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"08/01/2026 10:27:44"},{"role":"client","text":"Bom dia, tive um problema no pagamento da parcela do mes 12 da pós graduação, e não computou, porém agora que vi e está no valor de 336,39, o valor que pago é 98,42, poderiam checar? obrigado.","time":"08/01/2026 10:28:00"},{"role":"client","tex