INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4d61129c-ad47-4fac-9227-caef863ee4fa$tag$, $tag$2026010800175$tag$, $tag$prado (5512997088744)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"08/01/2026 16:30:35"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"08/01/2026 16:30:35"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"08/01/2026 16:32:13"},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"08/01/2026 16:32:37","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"08/01/2026 16:32:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá Thayanne... obrigado 😊","time":"08/01/2026 16:32:46"},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"08/01/2026 16:32:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"08/01/2026 16:32:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Qualquer dúvida é só chamar","time":"08/01/2026 16:33:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"09/01/2026 08:11:41","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nprado, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 16:35:27"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/696186587b03acb8ec073b87)","time":"09/01/2026 19:51:04"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"12/01/2026 19:49:06"},{"role":"client","text":"Sua sessão expirou!","time":"12/01/2026 19:51:07"}]$tag$, $tag$2026-01-08 16:30:35+00$tag$, FALSE, FALSE, 7, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 5, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0d301a52-015b-4493-af08-6d39758b4036$tag$, $tag$2026010800177$tag$, $tag$2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento (5585986596768)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Olá","time":"08/01/2026 16:52:51"},{"role":"client","text":"🌟 Boa tarde 2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento! Que alegria ter você aqui com a gente! 🙌","time":"08/01/2026 16:52:52"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"08/01/2026 16:52:56"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"08/01/2026 16:53:00"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"08/01/2026 16:53:04"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"08/01/2026 16:53:09"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"08/01/2026 16:53:16"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"08/01/2026 16:53:17"},{"role":"client","text":"Sim, concordo","time":"08/01/2026 16:53:31"},{"role":"client","text":"✅ Obrigado, 2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"08/01/2026 16:53:32"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"08/01/2026 16:53:36"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"08/01/2026 16:53:51"},{"role":"client","text":"Olá! 2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"08/01/2026 16:53:52"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"08/01/2026 16:53:56"},{"role":"client","text":"Sou aluno e quero ajuda","time":"08/01/2026 16:54:10"},{"role":"client","text":"Claro! Vamos te ajudar o mais rápido possível. Selecione no menu abaixo qual tipo de ajuda você precisa:","time":"08/01/2026 16:54:14"},{"role":"client","text":"Acesso ao portal","time":"08/01/2026 16:54:32"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"08/01/2026 16:54:32"},{"role":"client","text":"Então, fiz minha inscrição para pós em Psicoteologia mas ainda não me informaram data de início e acesso ao portal.","time":"08/01/2026 16:55:30"},{"role":"client","text":"Abel Alves transferiu o atendimento para a equipe FICV - COMERCIAL","time":"08/01/2026 16:59:17"},{"role":"client","text":"Ok","time":"08/01/2026 17:00:58"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"08/01/2026 17:04:54"},{"role":"agent","text":"*Thayanne Sales:* Olá boa tarde!\n\nPsicoteologia terá inicio em 23/02 e o acesso será enviado em fevereiro até a data do inicio das aulas no seu e-mail \n","time":"08/01/2026 17:05:48","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Caramba, tá certo!!! Tô meio ansioso pra começar kkkkk","time":"08/01/2026 17:08:45"},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"08/01/2026 17:09:06","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não, obrigado","time":"08/01/2026 17:09:23"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia.","time":"09/01/2026 08:12:28","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\n2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 08:12:33"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"09/01/2026 08:12:35"},{"role":"client","text":"2021.2 TEO EAD Alisson Naftali Carvalho do Nascimento, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"09/01/2026 08:27:36"}]$tag$, $tag$2026-01-08 16:52:51+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has