INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$37ec20bc-738f-4eb2-9d8c-eeb89fb45948$tag$, $tag$2026010900064$tag$, $tag$Giovani (5551983055204)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"09/01/2026 11:40:58"},{"role":"client","text":"🌟 Bom dia Giovani! Que alegria ter você aqui com a gente! 🙌","time":"09/01/2026 11:40:59"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/01/2026 11:41:04"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/01/2026 11:41:08"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"09/01/2026 11:41:12"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"09/01/2026 11:41:18"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"09/01/2026 11:41:23"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"09/01/2026 11:41:24"},{"role":"client","text":"Sim, concordo","time":"09/01/2026 11:42:05"},{"role":"client","text":"✅ Obrigado, Giovani! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"09/01/2026 11:42:06"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 11:42:10"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/01/2026 11:42:29"},{"role":"client","text":"Olá! Giovani!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/01/2026 11:42:30"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/01/2026 11:42:33"},{"role":"client","text":"Saber sobre os cursos","time":"09/01/2026 11:42:48"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/01/2026 11:42:52"},{"role":"client","text":"Cursos livres","time":"09/01/2026 11:43:04"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você. \n\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"09/01/2026 11:43:05"},{"role":"client","text":"Curso de Teologia","time":"09/01/2026 11:43:24"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"09/01/2026 11:58:54"},{"role":"agent","text":"*Thayanne Sales:* Bom dia!","time":"09/01/2026 11:59:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Oi bom dia","time":"09/01/2026 11:59:13"},{"role":"agent","text":"*Thayanne Sales:* Você deseja saber sobre ou cursos livres ou a graduação em Teologia ?","time":"09/01/2026 11:59:20","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Cursos livres","time":"09/01/2026 11:59:37"},{"role":"client","text":"Teologia no momento","time":"09/01/2026 11:59:42"},{"role":"agent","text":"*Thayanne Sales:* https://cursos.ficv.edu.br/super_live_ficv/","time":"09/01/2026 12:01:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6961185dc1c6dd3c0603f768)","time":"09/01/2026 12:01:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Esses são os cursos livres ","time":"09/01/2026 12:01:57","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nGiovani, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/01/2026 08:09:03"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/01/2026 08:09:04"},{"role":"client","text":"Giovani, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/01/2026 08:24:05"}]$tag$, $tag$2026-01-09 11:40:58+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_sco